import {
  ValidationOptions,
  ValidatorConstraint,
  ValidatorConstraintInterface,
  registerDecorator,
} from 'class-validator';

import { isValidTronAddress } from '../crypto-utils';

/**
 * Validator constraint for Tron address validation.
 */
@ValidatorConstraint({ name: 'isTronAddress', async: false })
export class IsTronAddressConstraint implements ValidatorConstraintInterface {
  validate(address: string): boolean {
    if (!address || typeof address !== 'string') {
      return false;
    }

    return isValidTronAddress(address);
  }

  defaultMessage(): string {
    return 'Invalid Tron address. Must start with T and be 34 characters (base58 encoded).';
  }
}

/**
 * Custom decorator to validate Tron (TRC-20) addresses.
 * @param validationOptions - Optional validation options
 */
export function IsTronAddress(validationOptions?: ValidationOptions) {
  return function (object: object, propertyName: string) {
    registerDecorator({
      target: object.constructor,
      propertyName,
      options: validationOptions,
      constraints: [],
      validator: IsTronAddressConstraint,
    });
  };
}

