import { applyDecorators } from '@nestjs/common';
import {
  ApiCreatedResponse,
  ApiNoContentResponse,
  ApiOkResponse,
  ApiOperation,
} from '@nestjs/swagger';

import { CryptoAddressResponseDto } from './dtos';

export function CreateCryptoAddressOpenApi() {
  return applyDecorators(
    ApiOperation({
      summary: 'Save crypto wallet address',
      description:
        'Saves a cryptocurrency wallet address for future deposits/withdrawals. Address is validated before saving. Currently supports Tron (TRC-20) only.',
    }),
    ApiCreatedResponse({
      description: 'Crypto address saved successfully',
      type: CryptoAddressResponseDto,
    }),
  );
}

export function GetCryptoAddressesOpenApi() {
  return applyDecorators(
    ApiOperation({
      summary: 'List saved crypto addresses',
      description:
        'Returns all saved cryptocurrency addresses for the current user, ordered by default first, then by creation date (newest first).',
    }),
    ApiOkResponse({
      description: 'List of saved crypto addresses',
      type: [CryptoAddressResponseDto],
    }),
  );
}

export function GetCryptoAddressOpenApi() {
  return applyDecorators(
    ApiOperation({
      summary: 'Get crypto address by ID',
      description:
        'Returns a specific saved crypto address. Only accessible by the owner.',
    }),
    ApiOkResponse({
      description: 'Crypto address details',
      type: CryptoAddressResponseDto,
    }),
  );
}

export function UpdateCryptoAddressOpenApi() {
  return applyDecorators(
    ApiOperation({
      summary: 'Update crypto address',
      description:
        'Update label or set as default. Setting as default automatically unsets other defaults. Cannot change the actual address.',
    }),
    ApiOkResponse({
      description: 'Crypto address updated successfully',
      type: CryptoAddressResponseDto,
    }),
  );
}

export function DeleteCryptoAddressOpenApi() {
  return applyDecorators(
    ApiOperation({
      summary: 'Delete crypto address',
      description:
        'Soft deletes the crypto address. If deleted address was default, the next most recent address is promoted to default.',
    }),
    ApiNoContentResponse({
      description: 'Crypto address deleted successfully',
    }),
  );
}

