 */
@Entity({
  name: 'saved_crypto_address',
})
@Index('idx_saved_crypto_address_wallet_address', ['walletId', 'address'], {
  unique: true,
  where: 'deleted_at IS NULL',
})
export class SavedCryptoAddressEntity extends BaseEntity {
  @ManyToOne(() => WalletEntity, { onDelete: 'CASCADE' })
  @JoinColumn({ name: 'wallet_id', referencedColumnName: 'id' })
  wallet: WalletEntity;

  @Index('idx_saved_crypto_address_wallet')
  @Column({ type: 'uuid', name: 'wallet_id' })
  walletId: string;

  @Column({
    name: 'network',
    type: 'enum',
