import { createHash } from 'crypto';

const BASE58_ALPHABET =
  '123456789ABCDEFGHJKLMNPQRSTUVWXYZabcdefghijkmnopqrstuvwxyz';

/**
 * Decodes a Base58-encoded string to a Buffer.
 * Returns null if the string contains invalid characters.
 */
function decodeBase58(input: string): Buffer | null {
  let value = BigInt(0);
  const base = BigInt(58);

  for (const char of input) {
    const digit = BASE58_ALPHABET.indexOf(char);
    if (digit === -1) return null;
    value = value * base + BigInt(digit);
  }

  // Count leading zeros (they map to 0x00 bytes)
  let leadingZeros = 0;
  for (const char of input) {
    if (char !== '1') break;
    leadingZeros++;
  }

  const bytes: number[] = [];
  while (value > BigInt(0)) {
    bytes.unshift(Number(value & BigInt(0xff)));
    value >>= BigInt(8);
  }

  return Buffer.from([...new Array(leadingZeros).fill(0), ...bytes]);
}

/**
 * Validates a Tron (TRC-20) wallet address.
 * Rules: starts with T, exactly 34 chars, base58, valid Base58Check checksum.
 */
export function isValidTronAddress(address: string): boolean {
  if (!address || typeof address !== 'string') return false;
  if (!address.startsWith('T') || address.length !== 34) return false;

  const decoded = decodeBase58(address);
  if (!decoded || decoded.length !== 25) return false;

  const payload = decoded.subarray(0, 21);
  const checksum = decoded.subarray(21);
  const hash = createHash('sha256')
    .update(createHash('sha256').update(payload).digest())
    .digest();

  return (
    hash[0] === checksum[0] &&
    hash[1] === checksum[1] &&
    hash[2] === checksum[2] &&
    hash[3] === checksum[3]
  );
}

/**
 * Validates an Ethereum-compatible address (Ethereum, Base, Polygon).
 * Rules: starts with 0x, exactly 42 chars, valid hex.
 */
export function isValidEthereumAddress(address: string): boolean {
  if (!address || typeof address !== 'string') return false;
  return /^0x[0-9a-fA-F]{40}$/.test(address);
}

/**
 * Validates a Solana wallet address.
 * Rules: Base58-encoded, decodes to exactly 32 bytes.
 */
export function isValidSolanaAddress(address: string): boolean {
  if (!address || typeof address !== 'string') return false;
  const decoded = decodeBase58(address);
  return decoded !== null && decoded.length === 32;
}

/**
 * Normalizes a crypto address by trimming whitespace.
 */
export function normalizeTronAddress(address: string): string {
  return address.trim();
}

