import {
  ValidationArguments,
  ValidationOptions,
  ValidatorConstraint,
  ValidatorConstraintInterface,
  registerDecorator,
} from 'class-validator';

import { CryptoNetwork } from '@/db/entities/saved-crypto-address.entity';
import {
  isValidEthereumAddress,
  isValidSolanaAddress,
  isValidTronAddress,
} from '../crypto-utils';

@ValidatorConstraint({ name: 'isCryptoAddress', async: false })
export class IsCryptoAddressConstraint implements ValidatorConstraintInterface {
  validate(address: string, args: ValidationArguments): boolean {
    if (!address || typeof address !== 'string') return false;

    const network = (args.object as Record<string, unknown>).network;

    switch (network) {
      case CryptoNetwork.Tron:
        return isValidTronAddress(address);
      case CryptoNetwork.Ethereum:
      case CryptoNetwork.Base:
      case CryptoNetwork.Polygon:
        return isValidEthereumAddress(address);
      case CryptoNetwork.Solana:
        return isValidSolanaAddress(address);
      default:
        return false;
    }
  }

  defaultMessage(): string {
    return 'INVALID_ADDRESS';
  }
}

export function IsCryptoAddress(validationOptions?: ValidationOptions) {
  return function (object: object, propertyName: string) {
    registerDecorator({
      target: object.constructor,
      propertyName,
      options: validationOptions,
      constraints: [],
      validator: IsCryptoAddressConstraint,
    });
  };
}

